var seed = GetInt(parameters, "seed", context.Seed);
var trunkColor = GetColor(parameters, "trunkColor", System.Windows.Media.Color.FromRgb(100, 65, 30));
var leafColor = GetColor(parameters, "leafColor", System.Windows.Media.Color.FromRgb(50, 150, 50));
var leafColor2 = GetColor(parameters, "leafColor2", System.Windows.Media.Color.FromRgb(80, 200, 60));
var trunkWidth = GetFloat(parameters, "trunkWidth", 0.08f);
var trunkHeight = GetFloat(parameters, "trunkHeight", 0.4f);
var canopySize = GetFloat(parameters, "canopySize", 0.45f);
var pixelSize = Math.Max(1, GetInt(parameters, "pixelSize", 2));
var size = context.TileSize;
var result = new PixelBuffer(size, size);
var tR=trunkColor.R/255f; var tG=trunkColor.G/255f; var tB=trunkColor.B/255f;
var lR=leafColor.R/255f; var lG=leafColor.G/255f; var lB=leafColor.B/255f;
var l2R=leafColor2.R/255f; var l2G=leafColor2.G/255f; var l2B=leafColor2.B/255f;
var period = Math.Max(1, size);
var centerX = size / 2;
var trunkTop = (int)(size * (1f - trunkHeight));
var trunkPx = Math.Max(1, (int)(size * trunkWidth));
var canopyRadius = (int)(size * canopySize);
result.ParallelForEachPixel((x, y) =>
{
    var dx = x - centerX;
    var dy = y - trunkTop;
    var dist = MathF.Sqrt(dx*dx + dy*dy);
    var noiseMask = TileableFractalNoise(x * 0.05f, y * 0.05f, period, 2, 0.5f, 2f, seed);
    var trunkBase = size - 1;
    if (dist < canopyRadius * (0.8f + noiseMask * 0.3f))
    {
        var t = dist / canopyRadius;
        result.SetPixel(x, y, Lerp(l2R, lR, t), Lerp(l2G, lG, t), Lerp(l2B, lB, t), 1f);
    }
    else if (MathF.Abs(x - centerX) <= trunkPx && y >= trunkTop && y <= trunkBase)
    {
        result.SetPixel(x, y, tR, tG, tB, 1f);
    }
    else { result.SetPixel(x, y, 0, 0, 0, 0); }
});
return result;
}
